(window.webpackJsonp=window.webpackJsonp||[]).push([[850],{809:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> numOfSubarrays = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1e9</span>+<span class=\\"hljs-number\\">7</span>\\n    <span class=\\"hljs-keyword\\">let</span> odd=<span class=\\"hljs-number\\">0</span>, even=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n        sum+=arr[i]\\n        <span class=\\"hljs-keyword\\">if</span>(sum % <span class=\\"hljs-number\\">2</span> === <span class=\\"hljs-number\\">1</span>){\\n            odd++\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            even++\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=odd\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;arr.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(arr[i<span class=\\"hljs-number\\">-1</span>]%<span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">1</span>){\\n            odd--\\n            res=(res+<span class=\\"hljs-built_in\\">Math</span>.max(even,<span class=\\"hljs-number\\">0</span>)) % MOD\\n            <span class=\\"hljs-keyword\\">let</span> x=even\\n            even=odd\\n            odd=x\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            even--\\n            res=(res+<span class=\\"hljs-built_in\\">Math</span>.max(odd,<span class=\\"hljs-number\\">0</span>)) % MOD\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"number-of-sub-arrays-with-odd-sum","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>arr</code>&nbsp;\u3002\u8bf7\u4f60\u8fd4\u56de\u548c\u4e3a <strong>\u5947\u6570</strong>&nbsp;\u7684\u5b50\u6570\u7ec4\u6570\u76ee\u3002</p>\\n\\n<p>\u7531\u4e8e\u7b54\u6848\u53ef\u80fd\u4f1a\u5f88\u5927\uff0c\u8bf7\u4f60\u5c06\u7ed3\u679c\u5bf9&nbsp;<code>10^9 + 7</code>&nbsp;\u53d6\u4f59\u540e\u8fd4\u56de\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,3,5]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u7684\u5b50\u6570\u7ec4\u4e3a [[1],[1,3],[1,3,5],[3],[3,5],[5]] \u3002\\n\u6240\u6709\u5b50\u6570\u7ec4\u7684\u548c\u4e3a [1,4,9,3,8,5].\\n\u5947\u6570\u548c\u5305\u62ec [1,9,3,5] \uff0c\u6240\u4ee5\u7b54\u6848\u4e3a 4 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2 \uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [2,4,6]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u5b50\u6570\u7ec4\u4e3a [[2],[2,4],[2,4,6],[4],[4,6],[6]] \u3002\\n\u6240\u6709\u5b50\u6570\u7ec4\u548c\u4e3a [2,6,12,4,10,6] \u3002\\n\u6240\u6709\u5b50\u6570\u7ec4\u548c\u90fd\u662f\u5076\u6570\uff0c\u6240\u4ee5\u7b54\u6848\u4e3a 0 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,4,5,6,7]\\n<strong>\u8f93\u51fa\uff1a</strong>16\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [100,100,99,99]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [7]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= arr[i] &lt;= 100</code></li>\\n</ul>\\n","title":"1524. \u548c\u4e3a\u5947\u6570\u7684\u5b50\u6570\u7ec4\u6570\u76ee","relatedTags":["\u6570\u7ec4","\u6570\u5b66"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1524"}')}}]);